using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Default discriminator property renamed from
        // "Discriminator" to "$type". Preserve old property name so existing
        // documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: id format changed from "EntityType|Key" to just
        // "Key". Preserve the old format so existing documents with
        // "Blog|1"-style ids continue to work.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id")
            .ToJsonProperty("id");

        // Use IdProperty workaround – keep the legacy id format
        modelBuilder.Entity<Blog>().UsePropertyAccessMode(PropertyAccessMode.Property);

        // Breaking change 3: HasIndex() now throws on Cosmos (was silently
        // ignored in EF Core 8). Removed the unsupported call.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

